const item = $input.first().json;

// Tronque le body pour pas saturer le prompt (seuil 1500 chars)
const bodyRaw = item.textPlain || item.text || item.snippet || '';
const bodyTruncated = bodyRaw.substring(0, 1500);

// Extract from / subject / date
const from = item.from?.value?.[0]?.address || item.from || 'unknown';
const subject = item.subject || '(sans sujet)';
const date = item.internalDate || new Date().toISOString();

return [{
  json: {
    message_id: item.id,
    thread_id: item.threadId,
    from: from,
    subject: subject,
    body: bodyTruncated,
    date: date,
    // On prépare un bloc texte propre pour le prompt
    prompt_input: `From: ${from}\nSubject: ${subject}\nBody: ${bodyTruncated}`
  }
}];

const raw = $input.first().json.message?.content 
         || $input.first().json.output 
         || $input.first().json.text 
         || '{}';

let parsed;
try {
  // Strip potentielles backticks markdown si le modèle en ajoute
  const clean = raw.replace(/```json|```/g, '').trim();
  parsed = JSON.parse(clean);
} catch (e) {
  // Fallback si JSON invalide → catégorise en PERSO par défaut (safe)
  parsed = {
    category: 'PERSO',
    confidence: 0,
    action_suggested: 'read_later',
    one_line_summary: 'Erreur parse JSON, à revoir manuellement'
  };
}

// Récupère les metadata du mail original
const mailData = $('Code in JavaScript').first().json;

return [{
  json: {
    ...parsed,
    message_id: mailData.message_id,
    thread_id: mailData.thread_id,
    from: mailData.from,
    subject: mailData.subject
  }
}];

